function passFilter(v, f) {
  if (v === null || v === undefined || isNaN(v)) return false;
  if (f.min !== null && f.min !== undefined && v < f.min) return false;
  if (f.max !== null && f.max !== undefined && v > f.max) return false;
  return true;
}

function computeFunnel(basket) {
  const { filters } = BASKETS[basket];
  const universe = RAW.filter(r => r.d2 !== null);
  const stages = [];
  let pool = [...universe];
  for (const f of filters) {
    pool = pool.filter(r => passFilter(r[f.k], f));
    stages.push({ count: pool.length, symbols: pool.map(r => r.s) });
  }
  return { stages, universe: universe.length, qualified: pool };
}

const BASKET_KEYS = Object.keys(BASKETS);

export default function V8BasketFunnel() {
  const [basket, setBasket] = useState("buy_reversal");
  const [view, setView] = useState("funnel");
  const [hovCol, setHovCol] = useState(null);

  const cfg = BASKETS[basket];
  const { stages, universe, qualified } = computeFunnel(basket);
  const C = cfg.color;
  const isBuy = cfg.side === "BUY";

  return (
    <div style={{ fontFamily:"'DM Mono','Roboto Mono',monospace", background:"#070b12", minHeight:"100vh", color:"#c9d1e0", padding:"16px" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Mono:wght@300;400;500&family=Syne:wght@600;700;800&display=swap');
        *{box-sizing:border-box}
        ::-webkit-scrollbar{height:3px;width:3px}
        ::-webkit-scrollbar-thumb{background:#1f2937;border-radius:2px}
        .bk-tab{padding:7px 12px;border:1px solid #1a2535;background:transparent;color:#4b5563;cursor:pointer;font-family:inherit;font-size:10px;letter-spacing:.1em;text-transform:uppercase;transition:all .15s;white-space:nowrap}
        .bk-tab.active{color:#0a0e17;font-weight:600}
        .bk-tab:hover:not(.active){border-color:#2d3d52;color:#9ca3af}
        .vt{padding:5px 8px;border:1px solid #1a2535;background:transparent;color:#4b5563;cursor:pointer;font-family:inherit;font-size:10px;letter-spacing:.08em;text-transform:uppercase;transition:all .15s}
        .vt.active{border-color:#374151;color:#e5e7eb;background:#111827}
        .qs-card{padding:8px 12px;border:1px solid #1a2535;border-radius:3px;margin-bottom:5px}
      `}</style>

      <div style={{ marginBottom:14 }}>
        <div style={{ fontFamily:"'Syne',sans-serif", fontSize:20, fontWeight:800, color:C, letterSpacing:"-0.02em" }}>
          V8 BASKET FUNNEL
        </div>
        <div style={{ fontSize:10, color:"#374151", letterSpacing:".1em", marginTop:1 }}>
          SCORR · LIVE · {new Date().toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}).toUpperCase()}
        </div>
      </div>

      <div style={{ overflowX:"auto", marginBottom:14, paddingBottom:2 }}>
        <div style={{ display:"flex", gap:0, minWidth:"max-content", borderBottom:`1px solid ${C}22` }}>
          {BASKET_KEYS.map(k => {
            const b = BASKETS[k];
            const isActive = basket === k;
            const fc = computeFunnel(k).qualified.length;
            return (
              <button key={k} className={`bk-tab ${isActive?"active":""}`}
                onClick={() => { setBasket(k); setView("funnel"); setHovCol(null); }}
                style={isActive ? { background:b.color, borderColor:b.color, color:"#0a0e17" } : { borderColor: "#1a2535" }}>
                {b.label}
                <span style={{ marginLeft:5, background: isActive ? "rgba(0,0,0,0.25)" : "#1a2535", borderRadius:2, padding:"1px 5px", fontSize:9 }}>
                  {fc}
                </span>
              </button>
            );
          })}
        </div>
      </div>

      <div style={{ display:"flex", gap:20, marginBottom:14, flexWrap:"wrap" }}>
        {[["Side",cfg.side],["Target",cfg.target],["Win %",cfg.win],["Signals",cfg.sigs],["Universe",universe],["Qualified",qualified.length]].map(([k,v]) => (
          <div key={k}>
            <div style={{ fontSize:8, color:"#374151", letterSpacing:".1em", marginBottom:1 }}>{k}</div>
            <div style={{ fontSize:15, fontWeight:500, color: k==="Qualified" ? C : k==="Side" ? C : "#e5e7eb" }}>{v}</div>
          </div>
        ))}
      </div>

      <div style={{ display:"flex", gap:0, marginBottom:16 }}>
        {["funnel","stocks"].map(v => (
          <button key={v} className={`vt ${view===v?"active":""}`} onClick={() => setView(v)}>
            {v === "funnel" ? "Filter Funnel" : "Qualified Stocks"}
          </button>
        ))}
      </div>

      {view === "funnel" && (
        <div style={{ overflowX:"auto" }}>
          <div style={{ minWidth: Math.max(700, stages.length * 80 + 130) }}>
            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1, marginBottom:2 }}>
              <div style={{ fontSize:8, color:"#2d3d52", padding:"3px 0", letterSpacing:".08em" }}>DROP %</div>
              {stages.map((st,i) => {
                const prev = i===0 ? universe : stages[i-1].count;
                const dp = prev===0 ? 0 : Math.round(((prev-st.count)/prev)*100);
                return <div key={i} onMouseEnter={()=>setHovCol(i)} onMouseLeave={()=>setHovCol(null)}
                  style={{ textAlign:"center", fontSize:10, padding:"3px 2px",
                    color: dp>40?"#ef4444":dp>15?"#f97316":"#4b5563",
                    fontWeight: dp>40?600:400,
                    background: hovCol===i?`${C}12`:"transparent", transition:"background .1s" }}>
                  {dp===0?"—":`-${dp}%`}
                </div>;
              })}
            </div>

            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1, marginBottom:1 }}>
              <div style={{ fontSize:8, color:"#2d3d52", padding:"5px 0" }}>FILTER</div>
              {cfg.filters.map((f,i) => (
                <div key={i} onMouseEnter={()=>setHovCol(i)} onMouseLeave={()=>setHovCol(null)}
                  style={{ background: hovCol===i?`${C}20`:"#0d1117", padding:"5px 3px 2px", textAlign:"center",
                    fontSize:9, color:"#9ca3af", fontWeight:500, letterSpacing:".05em",
                    borderBottom:`2px solid ${C}`, transition:"background .1s" }}>
                  {f.l}
                </div>
              ))}
            </div>

            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1, marginBottom:1 }}>
              <div style={{ fontSize:8, color:"#2d3d52", padding:"2px 0" }}>THRESHOLD</div>
              {cfg.filters.map((f,i) => (
                <div key={i} onMouseEnter={()=>setHovCol(i)} onMouseLeave={()=>setHovCol(null)}
                  style={{ background: hovCol===i?`${C}12`:"#080c15", padding:"3px 2px", textAlign:"center",
                    fontSize:8, color:C, letterSpacing:".03em" }}>
                  {f.d}
                </div>
              ))}
            </div>

            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1, marginBottom:4 }}>
              <div style={{ fontSize:8, color:"#2d3d52", padding:"6px 0" }}>PASS COUNT</div>
              {stages.map((st,i) => (
                <div key={i} onMouseEnter={()=>setHovCol(i)} onMouseLeave={()=>setHovCol(null)}
                  style={{ background: hovCol===i?C:`${C}cc`, padding:"5px 3px", textAlign:"center",
                    fontSize:14, fontFamily:"'Syne',sans-serif", fontWeight:700, color:"#fff",
                    transition:"background .1s" }}>
                  {st.count}
                </div>
              ))}
            </div>

            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1, marginBottom:16 }}>
              <div />
              {stages.map((st,i) => {
                const h = Math.max(3, Math.round((st.count/universe)*80));
                return (
                  <div key={i} onMouseEnter={()=>setHovCol(i)} onMouseLeave={()=>setHovCol(null)}
                    style={{ display:"flex", alignItems:"flex-end", height:90, padding:"0 3px" }}>
                    <div style={{ width:"100%", height:h, borderRadius:"2px 2px 0 0",
                      background: hovCol===i
                        ? (isBuy ? "linear-gradient(180deg,#86efac,#22c55e)" : "linear-gradient(180deg,#fca5a5,#ef4444)")
                        : (isBuy ? "linear-gradient(180deg,#22c55e,#14532d)" : "linear-gradient(180deg,#ef4444,#7f1d1d)"),
                      transition:"height .3s ease", position:"relative" }}>
                      <div style={{ position:"absolute", top:-13, left:0, right:0, textAlign:"center", fontSize:8, color:"#374151" }}>
                        {st.count}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div style={{ fontSize:9, color:"#2d3d52", marginBottom:6, letterSpacing:".06em" }}>STOCKS AT EACH STAGE</div>
            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${stages.length},1fr)`, gap:1 }}>
              <div />
              {stages.map((st,ci) => (
                <div key={ci} onMouseEnter={()=>setHovCol(ci)} onMouseLeave={()=>setHovCol(null)}
                  style={{ background: hovCol===ci?`${C}08`:"transparent", padding:"3px 2px", minHeight:8 }}>
                  {st.symbols.map(sym => (
                    <div key={sym} style={{
                      fontSize:8, padding:"1px 0",
                      color: ci===stages.length-1 ? C : "#2d3d52",
                      fontWeight: ci===stages.length-1 ? 600 : 400,
                      borderBottom:"1px solid #0d1117",
                      letterSpacing:".03em"
                    }}>{sym}</div>
                  ))}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {view === "stocks" && (
        <div>
          <div style={{ fontSize:10, color:"#4b5563", marginBottom:10 }}>
            {qualified.length === 0 ? "No stocks qualify today" : `${qualified.length} stock${qualified.length!==1?"s":""} — all ${cfg.filters.length} filters passed`}
          </div>
          {qualified.length === 0 ? (
            <div style={{ padding:24, textAlign:"center", color:"#2d3d52", border:"1px solid #1a2535", borderRadius:4, fontSize:12 }}>
              No signals today for {cfg.label}
            </div>
          ) : (
            qualified.map(r => (
              <div key={r.s} className="qs-card" style={{ borderLeft:`3px solid ${C}` }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:5 }}>
                  <span style={{ fontFamily:"'Syne',sans-serif", fontWeight:700, color:C, fontSize:13 }}>{r.s}</span>
                  <span style={{ fontSize:8, color:C, background:`${C}15`, padding:"2px 7px", borderRadius:2, letterSpacing:".08em" }}>
                    {cfg.side} {cfg.target}
                  </span>
                </div>
                <div style={{ display:"grid", gridTemplateColumns:"repeat(5,1fr)", gap:6 }}>
                  {cfg.filters.map(f => (
                    <div key={f.k}>
                      <div style={{ fontSize:7, color:"#374151", marginBottom:1 }}>{f.l}</div>
                      <div style={{ fontSize:11, color:"#9ca3af" }}>{r[f.k]?.toFixed?.(1) ?? "—"}</div>
                    </div>
                  ))}
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
